### Full Peer Example

```javascript
const PeerInstance = new ZYNQ.peer({
  video: true,
  audio: true,
  txt: true
})

PeerInstance.on("open", id => {
  console.log("My ID:", id)
})

PeerInstance.on("data", msg => {
  console.log("Received:", msg)
})

PeerInstance.on("stream", stream => {
  remoteVideo.srcObject = stream
})

// Connect to someone
PeerInstance.connect("other-peer-id")

// Send a message
PeerInstance.send("hello ­¤æĮ")
```
